<?php
date_default_timezone_set('Asia/Manila');
function stt_nd($v){$v=trim((string)$v);if($v==='')return null;foreach(['m/d/Y','m-d-Y','Y-m-d'] as $f){$d=DateTime::createFromFormat($f,$v);if($d instanceof DateTime)return $d->format('Y-m-d');}$t=strtotime($v);return $t===false?null:date('Y-m-d',$t);} 
function stt_fd($v){$t=strtotime((string)$v);return $t===false?'':date('m/d/Y',$t);} 
function stt_nextdocval($v){$v=trim((string)$v);if($v===''||!preg_match('/^(STT-)(\d+)$/',$v,$m))return 'STT-0000001';return $m[1].str_pad((string)(((int)$m[2])+1),strlen($m[2]),'0',STR_PAD_LEFT);} 
function stt_nextdoc($link){$s=$link->prepare("SELECT docnum FROM tranfile1 WHERE trncde='STT' ORDER BY docnum DESC LIMIT 1");$s->execute();$r=$s->fetch(PDO::FETCH_ASSOC);return stt_nextdocval($r['docnum']??'');}
function stt_userdesc($link,$u){$u=trim((string)$u);if($u==='')return ''; $s=$link->prepare("SELECT userdesc FROM users WHERE usercode=? LIMIT 1");$s->execute([$u]);$r=$s->fetch(PDO::FETCH_ASSOC);return $r['userdesc']??'';}
function stt_itemdesc($link,$i){$s=$link->prepare("SELECT itmdsc FROM itemfile WHERE itmcde=? LIMIT 1");$s->execute([$i]);$r=$s->fetch(PDO::FETCH_ASSOC);return $r['itmdsc']??'';}
function stt_wops($link){$a=[];$s=$link->prepare("SELECT warcde,warehouse_name FROM warehouse ORDER BY warehouse_name ASC");$s->execute();while($r=$s->fetch(PDO::FETCH_ASSOC))$a[]=$r;return $a;}
function stt_fmap($link){$m=[];$s=$link->prepare("SELECT warehouse_floor_id,warcde,floor_no,floor_name FROM warehouse_floor ORDER BY floor_no ASC,floor_name ASC,warehouse_floor_id ASC");$s->execute();while($r=$s->fetch(PDO::FETCH_ASSOC)){if(!isset($m[$r['warcde']]))$m[$r['warcde']]=[];$m[$r['warcde']][]=['warehouse_floor_id'=>$r['warehouse_floor_id'],'floor_no'=>trim((string)($r['floor_no']!==''?$r['floor_no']:$r['floor_name']))];}return $m;}
function stt_sops($link){$a=[];$s=$link->prepare("SELECT warehouse_staff_id,fname,lname FROM warehouse_staff ORDER BY fname ASC,lname ASC");$s->execute();while($r=$s->fetch(PDO::FETCH_ASSOC))$a[]=['warehouse_staff_id'=>$r['warehouse_staff_id'],'staff_name'=>trim($r['fname'].' '.$r['lname'])];return $a;}
function stt_qm($n){return implode(',',array_fill(0,max(0,(int)$n),'?'));}
function stt_curstock($link,$it,$wa,$fl,$dt,$ex=[]){$it=trim((string)$it);$wa=trim((string)$wa);$fl=trim((string)$fl);$dt=trim((string)$dt);if($it===''||$wa===''||$fl===''||$dt==='')return 0;$sql="SELECT COALESCE(SUM(t2.stkqty),0) current_stock FROM tranfile1 t1 LEFT JOIN tranfile2 t2 ON t1.docnum=t2.docnum WHERE t2.warcde=? AND t2.warehouse_floor_id=? AND t1.trndte<=? AND t2.itmcde=?";$p=[$wa,$fl,$dt,$it];$ids=[];foreach($ex as $id){$id=(int)$id;if($id>0)$ids[]=$id;}if($ids){$sql.=" AND t2.recid NOT IN (".stt_qm(count($ids)).")";$p=array_merge($p,$ids);} $s=$link->prepare($sql);$s->execute($p);$r=$s->fetch(PDO::FETCH_ASSOC);return (float)($r['current_stock']??0);}
function stt_header($link,$doc){$s=$link->prepare("SELECT * FROM tranfile1 WHERE docnum=? AND trncde='STT' LIMIT 1");$s->execute([$doc]);return $s->fetch(PDO::FETCH_ASSOC);} 
function stt_savehead($link,$doc,$dt,$ord,$rem,$user){$h=stt_header($link,$doc);$u=trim((string)($h['usercode']??''));if($u==='')$u=trim((string)$user);$d=['docnum'=>$doc,'cuscde'=>null,'trntot'=>0,'trndte'=>$dt,'ordernum'=>$ord,'remarks'=>$rem,'usercode'=>$u,'trncde'=>'STT'];if(empty($h))PDO_InsertRecord($link,'tranfile1',$d,false);else{unset($d['docnum']);PDO_UpdateRecord($link,'tranfile1',$d,'recid = ?',[$h['recid']],false);} $s=$link->prepare("UPDATE tranfile2 SET trndte=?,trncde='STT',untprc=0,extprc=0 WHERE docnum=?");$s->execute([$dt,$doc]);}
function stt_linepair($link,$doc,$dt,$it,$qty,$fwa,$ffl,$twa,$tfl,$staff,$batch=''){if($batch==='')$batch='STTLINE-'.date('YmdHis').'-'.mt_rand(1000,9999);$c=['docnum'=>$doc,'trncde'=>'STT','trndte'=>$dt,'itmcde'=>$it,'itmqty'=>(float)$qty,'untprc'=>0,'extprc'=>0,'file_batchno'=>$batch,'warehouse_staff_id'=>$staff];$a=$c;$a['stkqty']=-1*abs((float)$qty);$a['warcde']=$fwa;$a['warehouse_floor_id']=$ffl;$b=$c;$b['stkqty']=abs((float)$qty);$b['warcde']=$twa;$b['warehouse_floor_id']=$tfl;PDO_InsertRecord($link,'tranfile2',$a,false);PDO_InsertRecord($link,'tranfile2',$b,false);} 
function stt_rows($link,$doc){$sql="SELECT t.recid,t.itmcde,t.itmqty,t.stkqty,t.warcde,t.warehouse_floor_id,t.warehouse_staff_id,t.file_batchno,i.itmdsc,w.warehouse_name,f.floor_no,f.floor_name,ws.fname,ws.lname FROM tranfile2 t LEFT JOIN itemfile i ON i.itmcde=t.itmcde LEFT JOIN warehouse w ON w.warcde=t.warcde LEFT JOIN warehouse_floor f ON f.warehouse_floor_id=t.warehouse_floor_id LEFT JOIN warehouse_staff ws ON ws.warehouse_staff_id=t.warehouse_staff_id WHERE t.docnum=? AND t.trncde='STT' ORDER BY t.file_batchno ASC,t.recid ASC";$s=$link->prepare($sql);$s->execute([$doc]);return $s->fetchAll(PDO::FETCH_ASSOC);} 
function stt_group($rows){$g=[];foreach($rows as $r){$k=trim((string)($r['file_batchno']??''));if($k==='')$k='recid_'.$r['recid'];if(!isset($g[$k]))$g[$k]=[];$g[$k][]=$r;} $out=[];foreach($g as $set){$src=null;$dst=null;foreach($set as $r){$q=(float)($r['stkqty']??0);if($q<0&&$src===null)$src=$r;elseif($q>0&&$dst===null)$dst=$r;} if($src===null&&isset($set[0]))$src=$set[0]; if($dst===null){foreach($set as $r){if($src===null||(int)$r['recid']!==(int)$src['recid']){$dst=$r;break;}}} $qty=$src!==null&&isset($src['stkqty'])&&$src['stkqty']!=0?abs((float)$src['stkqty']):($dst!==null&&isset($dst['stkqty'])&&$dst['stkqty']!=0?abs((float)$dst['stkqty']):abs((float)($src['itmqty']??0))); $sf=''; if($src!==null)$sf=trim((string)(($src['floor_no']??'')!==''?$src['floor_no']:($src['floor_name']??''))); $tf=''; if($dst!==null)$tf=trim((string)(($dst['floor_no']??'')!==''?$dst['floor_no']:($dst['floor_name']??''))); $staff=''; if($src!==null)$staff=trim((($src['fname']??'').' '.($src['lname']??''))); if($staff===''&&$dst!==null)$staff=trim((($dst['fname']??'').' '.($dst['lname']??''))); $out[]=['recid'=>(int)($src['recid']??$set[0]['recid']??0),'file_batchno'=>$src['file_batchno']??($dst['file_batchno']??''),'item_code'=>$src['itmcde']??($dst['itmcde']??''),'item_desc'=>$src['itmdsc']??($dst['itmdsc']??''),'qty'=>$qty,'warehouse_from'=>$src['warehouse_name']??'','warehouse_floor_from'=>$sf,'warehouse_to'=>$dst['warehouse_name']??'','warehouse_floor_to'=>$tf,'warehouse_staff'=>$staff];} return $out;}
function stt_render($lines){if(!$lines)return ['html'=>"<tr><td colspan='7' class='text-center text-muted py-4'>No stock transfer records yet.</td></tr>",'html_mobile'=>"<tr><td class='text-center text-muted py-4'>No stock transfer records yet.</td></tr>"]; $h="<tr><th>Item</th><th style='text-align:right'>Quantity</th><th>Warehouse From</th><th>Floor From</th><th>Warehouse To</th><th>Floor To</th><th class='text-center'>Action</th></tr>";$m='';foreach($lines as $l){$h.="<tr><td>".htmlspecialchars((string)$l['item_desc'],ENT_QUOTES)."</td><td style='text-align:right'>".number_format((float)$l['qty'],2)."</td><td>".htmlspecialchars((string)$l['warehouse_from'],ENT_QUOTES)."</td><td>".htmlspecialchars((string)$l['warehouse_floor_from'],ENT_QUOTES)."</td><td>".htmlspecialchars((string)$l['warehouse_to'],ENT_QUOTES)."</td><td>".htmlspecialchars((string)$l['warehouse_floor_to'],ENT_QUOTES)."</td><td class='text-center'><div class='d-grid gap-2'><button type='button' class='btn btn-primary btn-sm fw-bold' onclick='salesfile2(\"getEdit\",{$l['recid']})'>Edit</button><button type='button' class='btn btn-danger btn-sm fw-bold' onclick='salesfile2(\"delete\",{$l['recid']})'>Delete</button></div></td></tr>"; $m.="<tr><td><div class='card shadow-sm border-0 mb-3'><div class='card-body'><div class='fw-bold mb-2'>".htmlspecialchars((string)$l['item_desc'],ENT_QUOTES)."</div><div><span class='fw-bold'>Quantity:</span> ".number_format((float)$l['qty'],2)."</div><div><span class='fw-bold'>Warehouse From:</span> ".htmlspecialchars((string)$l['warehouse_from'],ENT_QUOTES)."</div><div><span class='fw-bold'>Floor From:</span> ".htmlspecialchars((string)$l['warehouse_floor_from'],ENT_QUOTES)."</div><div><span class='fw-bold'>Warehouse To:</span> ".htmlspecialchars((string)$l['warehouse_to'],ENT_QUOTES)."</div><div><span class='fw-bold'>Floor To:</span> ".htmlspecialchars((string)$l['warehouse_floor_to'],ENT_QUOTES)."</div><div class='mt-3 d-grid gap-2'><button type='button' class='btn btn-primary btn-sm fw-bold' onclick='salesfile2(\"getEdit\",{$l['recid']})'>Edit</button><button type='button' class='btn btn-danger btn-sm fw-bold' onclick='salesfile2(\"delete\",{$l['recid']})'>Delete</button></div></div></div></td></tr>";} return ['html'=>$h,'html_mobile'=>$m];}
function stt_pairrows($link,$recid,$doc){$s=$link->prepare("SELECT * FROM tranfile2 WHERE recid=? AND docnum=? LIMIT 1");$s->execute([(int)$recid,$doc]);$r=$s->fetch(PDO::FETCH_ASSOC);if(empty($r))return []; $b=trim((string)($r['file_batchno']??''));if($b!==''){$s=$link->prepare("SELECT * FROM tranfile2 WHERE docnum=? AND file_batchno=? ORDER BY recid ASC");$s->execute([$doc,$b]);return $s->fetchAll(PDO::FETCH_ASSOC);} return [$r];}
