if($ev==='insert'||$ev==='submitEdit'){$ed=$ev==='submitEdit';$suf=$ed?'edit':'add';$dt=stt_nd($_POST['trndte_1']??'');$it=trim((string)($_POST['itmcde_'.$suf.'_hidden']??''));$qty=(float)str_replace(',','',(string)($_POST['itmqty_'.$suf]??'0'));$fwa=trim((string)($_POST['warcde_from_'.$suf]??''));$ffl=trim((string)($_POST['warehouse_floor_id_from_'.$suf]??''));$twa=trim((string)($_POST['warcde_to_'.$suf]??''));$tfl=trim((string)($_POST['warehouse_floor_id_to_'.$suf]??''));$staff=trim((string)($_POST['warehouse_staff_id_'.$suf]??'')); if($dt===null)$ret=['status'=>0,'msg'=>'<b>Tran. Date</b> cannot be empty.']; elseif($it==='')$ret=['status'=>0,'msg'=>'<b>Item</b> cannot be empty.']; elseif($qty<=0)$ret=['status'=>0,'msg'=>'<b>Quantity</b> cannot be empty or 0.']; elseif($fwa==='')$ret=['status'=>0,'msg'=>'<b>Warehouse From</b> cannot be empty.']; elseif($ffl==='')$ret=['status'=>0,'msg'=>'<b>Warehouse Floor From</b> cannot be empty.']; elseif($twa==='')$ret=['status'=>0,'msg'=>'<b>Warehouse To</b> cannot be empty.']; elseif($tfl==='')$ret=['status'=>0,'msg'=>'<b>Warehouse Floor To</b> cannot be empty.']; elseif($staff==='')$ret=['status'=>0,'msg'=>'<b>Warehouse Staff</b> cannot be empty.']; elseif($fwa===$twa&&$ffl===$tfl)$ret=['status'=>0,'msg'=>'<b>Warehouse From</b> and <b>Warehouse To</b> cannot be the same location.']; $ex=[];$batch=''; if(($ret['status']??1)===1&&$ed){$rows=stt_pairrows($link,(int)($_POST['recid']??0),$doc);foreach($rows as $r){$ex[]=(int)$r['recid'];if($batch===''&&!empty($r['file_batchno']))$batch=(string)$r['file_batchno'];}} if(($ret['status']??1)===1&&$qty>stt_curstock($link,$it,$fwa,$ffl,$dt,$ex))$ret=['status'=>0,'msg'=>'Insufficient quantity.']; if(($ret['status']??1)===1){stt_savehead($link,$doc,$dt,trim((string)($_POST['ordernum_1']??'')),trim((string)($_POST['remarks_1']??'')),$user); if($ed&&$ex){$s=$link->prepare("DELETE FROM tranfile2 WHERE recid IN (".stt_qm(count($ex)).")");$s->execute($ex);} stt_linepair($link,$doc,$dt,$it,$qty,$fwa,$ffl,$twa,$tfl,$staff,$batch);$r=stt_render(stt_group(stt_rows($link,$doc)));$ret=['status'=>1,'msg'=>$ed?'submitEdit':'insert','html'=>$r['html'],'html_mobile'=>$r['html_mobile']];} echo json_encode($ret);exit;}
