den" value="<?php echo htmlspecialchars($doc,ENT_QUOTES); ?>"><input type="hidden" name="recid_hidden" id="recid_hidden" value="<?php echo htmlspecialchars((string)($_POST['recid_hidden']??''),ENT_QUOTES); ?>"></form>
