l><select name="warehouse_floor_id_from_add" id="warehouse_floor_id_from_add" class="form-select"><option value="">Select Warehouse Floor</option></select></div><div class="col-md-6 col-12"><label>Warehouse Floor To</label><select name="warehouse_floor_id_to_add" id="warehouse_floor_id_to_add" class="form-select"><option value="">Select Warehouse Floor</option></select></div></div><div class="row m-3"><div class="col-12"><label>Warehouse Staff</label><select name="warehouse_staff_id_add" id="warehouse_staff_id_add" class="form-select"><option value="">Select Warehouse Staff</option><?php foreach($warehouse_staff_options as $o): ?><option value="<?php echo htmlspecialchars($o['warehouse_staff_id'],ENT_QUOTES); ?>"><?php echo htmlspecialchars($o['staff_name'],ENT_QUOTES); ?></option><?php endforeach; ?></select></div></div><div class="row m-2"><div class="error_msg_add_modal"></div></div></div><div class="modal-footer"><button type="button" class="btn btn-danger" data-bs-dismiss="modal">Cancel</button><button type="button" class="btn btn-primary" onclick="salesfile2('insert')">Save</button></div></div></div></div>
<div class="modal fade" id="edit_modal_sales" tabindex="-1"><div class="modal-dialog modal-lg"><div class="modal-content"><div class="modal-header"><h5 class="modal-title">Edit Stock Transfer</h5><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><div class="row m-3"><div class="col-12"><label>Item</label><div class="input-group"><input type="text" class="form-control" name="itmcde_edit" id="itmcde_edit" readonly placeholder="Enter item to search"><div class="input-group-append"><span class="input-group-text bg-success btn_search_item" onclick="search_itm_func('edit')" style='color:white;height:100%;border-top-left-radius:0;border-bottom-left-radius:0'><i class="fas fa-search"></i></span></div></div><input type="hidden" name="itmcde_edit_hidden" id="itmcde_edit_hidden"></div></div><div class="row m-3"><div class="col-12"><label>Quantity</label><input type="text" name="itmqty_edit" id="itmqty_edit" class="form-control" autocomplete="off"><div class="current-stock-text" id="current_stock_edit_text">Current Stock: 0.00</div></div></div><div class="row m-3"><div class="col-md-6 col-12"><label>Warehouse From</label><select name="warcde_from_edit" id="warcde_from_edit" class="form-select"><option value="">Select Warehouse</option><?php foreach($warehouse_options as $o): ?><option value="<?php echo htmlspecialchars($o['warcde'],ENT_QUOTES); ?>"><?php echo htmlspecialchars($o['warehouse_name'],ENT_QUOTES); ?></option><?php endforeach; ?></select></div><div class="col-md-6 col-12"><label>Warehouse To</label><select name="warcde_to_edit" id="warcde_to_edit" class="form-select"><option value="">Select Warehouse</option><?php foreach($warehouse_options as $o): ?><option value="<?php echo htmlspecialchars($o['warcde'],ENT_QUOTES); ?>"><?php echo htmlspecialchars($o['warehouse_name'],ENT_QUOTES); ?></option><?php endforeach; ?></select></div></div><div class="row m-3"><div class="col-md-6 col-12"><label>Warehouse Floor From</label><select name="warehouse_floor_id_from_edit" id="warehouse_floor_id_from_edit" class="form-select"><option value="">Select Warehouse Floor</option></select></div><div class="col-md-6 col-12"><label>Warehouse Floor To</label><select name="warehouse_floor_id_to_edit" id="warehouse_floor_id_to_edit" class="form-select"><option value="">Select Warehouse Floor</option></select></div></div><div class="row m-3"><div class="col-12"><label>Warehouse Staff</label><select name="warehouse_staff_id_edit" id="warehouse_staff_id_edit" class="form-select"><option value="">Select Warehouse Staff</option><?php foreach($warehouse_staff_options as $o): ?><option value="<?php echo htmlspecialchars($o['warehouse_staff_id'],ENT_QUOTES); ?>"><?php echo htmlspecialchars($o['staff_name'],ENT_QUOTES); ?></option><?php endforeach; ?></select></div></div><div class="row m-2"><div class="error_msg_edit_modal"></div></div></div><div class="modal-footer"><button type="button" class="btn btn-danger" data-bs-dismiss="modal">Cancel</button><button type="button" class="btn btn-primary" onclick="salesfile2('submitEdit')">Save</button></div></div></div><input type="hidden" name="salesfile2_recid_hidden" id="salesfile2_recid_hidden"></div>
<div class="modal fade" id="view_itm_search" tabindex="-1"><div class="modal-dialog"><div class="modal-content"><div class="modal-header"><h5 class="modal-title">Search Item</h5><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><div class="input-group mb-3"><input type="text" class="form-control" name="itm_view" id="itm_view" autocomplete="off"><div class="input-group-append"><span class="input-group-text bg-success btn_search_item" onclick="search_itm_func_inmodal()" style='color:white;height:100%;border-top-left-radius:0;border-bottom-left-radius:0'><i class="fas fa-search"></i></span></div></div><div class="error_msg_itm_view"></div><div class="html_itm_view_data" style="max-height:70vh;overflow:auto"></div></div><div class="modal-footer back_btn_modal_footer"></div></div></div></div><input type="hidden" id="xevent_itmsearch_hidden">
<script>
var ajaxUrl='stock_transfer_transaction_file2.php',floorMap=<?php echo json_encode($warehouse_floor_map); ?>;
function post(d,cb){d.stt_ajax='1';$.ajax({data:d,dataType:'json',type:'post',url:ajaxUrl,success:cb});}
function floors(id,w,s){var $x=$('#'+id),o="<option value=''>Select Warehouse Floor</option>",a=floorMap[w]||[];for(var i=0;i<a.length;i++){o+="<option value='"+a[i].warehouse_floor_id+"'"+((s&&s===a[i].warehouse_floor_id)?' selected':'')+">"+a[i].floor_no+"</option>";}$x.html(o);} 
function stocktxt(m,v){v=parseFloat(v);if(isNaN(v))v=0;$('#current_stock_'+m+'_text').text('Current Stock: '+v.toFixed(2));}
function refresh(m,cb){var it=$('#itmcde_'+m+'_hidden').val(),wa=$('#warcde_from_'+m).val(),fl=$('#warehouse_floor_id_from_'+m).val(),dt=$('#trndte_1').val();if(!it||!wa||!fl||!dt){stocktxt(m,0);if(cb)cb(0);return;} post({event_action:'get_current_stock',item_code:it,warcde:wa,warehouse_floor_id:fl,trndte:dt},function(r){stocktxt(m,r.current_stock||0);if(cb)cb(r.current_stock||0);});}
function strip(x){return $('<div>').html(x||'').text();}
function validate(m,cb){var it=$('#itmcde_'+m+'_hidden').val(),q=parseFloat(($('#itmqty_'+m).val()||'0').replace(/,/g,'')),fwa=$('#warcde_from_'+m).val(),ffl=$('#warehouse_floor_id_from_'+m).val(),twa=$('#warcde_to_'+m).val(),tfl=$('#warehouse_floor_id_to_'+m).val();if(!it||isNaN(q)||q<=0||!fwa||!ffl||!twa||!tfl){cb(true);return;} if(m==='edit'){cb(true);return;} refresh(m,function(cs){if(q>cs){alert('Insufficient quantity.');cb(false);return;} cb(true);});}
function loadrows(){post({event_action:'load_rows',docnum:$('#docnum_hidden').val()},function(r){$('#tbody_main').html(r.html||'');$('#tbody_main_mobile').html(r.html_mobile||'');});}
function back_page(){document.forms.myforms.target='_self';document.forms.myforms.method='post';document.forms.myforms.action='stock_transfer_transaction.php';document.forms.myforms.submit();}
function clearadd(){$('#itmcde_add').prop('readonly',false).val('');$('#itmcde_add_hidden').val('');$('#itmqty_add').val('');$('#warcde_from_add,#warcde_to_add,#warehouse_staff_id_add').val('');floors('warehouse_floor_id_from_add','','');floors('warehouse_floor_id_to_add','','');stocktxt('add',0);$('.error_msg_add_modal').html('');}
function select_item_modal(code,desc,m){if(m==='add'){$('#itmcde_add_hidden').val(code);$('#itmcde_add').val(desc).prop('readonly',true);$('#view_itm_search').modal('hide');$('#insert_modal_sales').modal('show');refresh('add');$('.error_msg_add_modal').html('');}else{$('#itmcde_edit_hidden').val(code);$('#itmcde_edit').val(desc);$('#view_itm_search').modal('hide');$('#edit_modal_sales').modal('show');refresh('edit');$('.error_msg_edit_modal').html('');} $('.error_msg_itm_view').html('');}
function back_from_view_func(m){$('#view_itm_search').modal('hide');if(m==='add')$('#insert_modal_sales').modal('show');else $('#edit_modal_sales').modal('show');}
function search_itm_func(m){var q=m==='add'?$('#itmcde_add').val():$('#itmcde_edit').val();$('#xevent_itmsearch_hidden').val(m);$('.back_btn_modal_footer').html("<button type='button' class='btn btn-danger' onclick='back_from_view_func("+JSON.stringify(m)+")'>Back</button>");post({event_action:'search_itm',search_itm:q,event_action_itmsearch:m},function(r){if(r.status===0){var h="<div class='alert alert-danger m-2' role='alert'>"+r.msg+"</div>";if(m==='add')$('.error_msg_add_modal').html(h);else $('.error_msg_edit_modal').html(h);return;} $('.html_itm_view_data').html(r.html||'');$('#itm_view').val(r.itm_search||'');$('.error_msg_itm_view').html('');if(m==='add')$('#insert_modal_sales').modal('hide');else $('#edit_modal_sales').modal('hide');$('#view_itm_search').modal('show');});}
function search_itm_func_inmodal(){post({event_action:'search_itm',search_itm:$('#itm_view').val(),event_action_itmsearch:$('#xevent_itmsearch_hidden').val()||'add'},function(r){if(r.status===0){$('.error_msg_itm_view').html("<div class='alert alert-danger m-2' role='alert'>"+r.msg+"</div>");return;} $('.html_itm_view_data').html(r.html||'');$('.error_msg_itm_view').html('');});}
function handle(ev,r){if(r.status===0){if(strip(r.msg)==='Insufficient quantity.'){alert('Insufficient quantity.');return;} if(ev==='insert')$('.error_msg_add_modal').html("<div class='alert alert-danger m-2' role='alert'>"+r.msg+"</div>");else if(ev==='submitEdit')$('.error_msg_edit_modal').html("<div class='alert alert-danger m-2' role='alert'>"+r.msg+"</div>");else{$('#alert_modal_body_system').html(r.msg);$('#alert_modal_system').modal('show');}return;} if(r.msg==='save_exit'){back_page();return;} if(r.msg==='save_new'){$('#docnum_1,#docnum_hidden').val(r.new_docnum||'');$('#ordernum_1').val('');$('#remarks_1').val('');$('#tbody_main').html("<tr><td colspan='8' class='text-center text-muted py-4'>No stock transfer records yet.</td></tr>");$('#tbody_main_mobile').html("<tr><td class='text-center text-muted py-4'>No stock transfer records yet.</td></tr>");return;} if(r.msg==='retEdit'){$('#salesfile2_recid_hidden').val(r.retEdit.recid||'');$('#itmcde_edit_hidden').val(r.retEdit.itmcde||'');$('#itmcde_edit').val(r.retEdit.itmdsc||'');$('#itmqty_edit').val(r.retEdit.itmqty||'');$('#warcde_from_edit').val(r.retEdit.warcde_from||'');floors('warehouse_floor_id_from_edit',r.retEdit.warcde_from||'',r.retEdit.warehouse_floor_id_from||'');$('#warcde_to_edit').val(r.retEdit.warcde_to||'');floors('warehouse_floor_id_to_edit',r.retEdit.warcde_to||'',r.retEdit.warehouse_floor_id_to||'');$('#warehouse_staff_id_edit').val(r.retEdit.warehouse_staff_id||'');stocktxt('edit',r.retEdit.current_stock||0);$('.error_msg_edit_modal').html('');$('#edit_modal_sales').modal('show');return;} if(ev==='insert')$('#insert_modal_sales').modal('hide'); if(ev==='submitEdit')$('#edit_modal_sales').modal('hide'); if(r.html!==undefined){$('#tbody_main').html(r.html||'');$('#tbody_main_mobile').html(r.html_mobile||'');}}
function salesfile2(ev,id){var doc=$('#docnum_hidden').val();if(ev==='open_add'){clearadd();$('#insert_modal_sales').modal('show');return;} if(ev==='getEdit'){post({event_action:'getEdit',docnum:doc,recid:id},function(r){handle(ev,r);});return;} if(ev==='delete'){if(!confirm('Are you sure you want to delete?'))return;post({event_action:'delete',docnum:doc,recid:id},function(r){handle(ev,r);});return;} if(ev==='save_exit'||ev==='save_new'){post({event_action:ev,docnum:doc,docnum_1:$('#docnum_1').val(),trndte_1:$('#trndte_1').val(),ordernum_1:$('#ordernum_1').val(),remarks_1:$('#remarks_1').val(),usercode_1:$('#usercode_1').val()},function(r){handle(ev,r);});return;} if(ev==='insert'||ev==='submitEdit'){var m=ev==='insert'?'add':'edit';validate(m,function(ok){if(!ok)return;var p={event_action:ev,docnum:doc,docnum_1:$('#docnum_1').val(),trndte_1:$('#trndte_1').val(),ordernum_1:$('#ordernum_1').val(),remarks_1:$('#remarks_1').val(),usercode_1:$('#usercode_1').val()}; if(m==='add'){$.extend(p,{itmcde_add_hidden:$('#itmcde_add_hidden').val(),itmqty_add:$('#itmqty_add').val(),warcde_from_add:$('#warcde_from_add').val(),warehouse_floor_id_from_add:$('#warehouse_floor_id_from_add').val(),warcde_to_add:$('#warcde_to_add').val(),warehouse_floor_id_to_add:$('#warehouse_floor_id_to_add').val(),warehouse_staff_id_add:$('#warehouse_staff_id_add').val()});}else{$.extend(p,{recid:$('#salesfile2_recid_hidden').val(),itmcde_edit_hidden:$('#itmcde_edit_hidden').val(),itmqty_edit:$('#itmqty_edit').val(),warcde_from_edit:$('#warcde_from_edit').val(),warehouse_floor_id_from_edit:$('#warehouse_floor_id_from_edit').val(),warcde_to_edit:$('#warcde_to_edit').val(),warehouse_floor_id_to_edit:$('#warehouse_floor_id_to_edit').val(),warehouse_staff_id_edit:$('#warehouse_staff_id_edit').val()});} post(p,function(r){handle(ev,r);});});}}
$(function(){loadrows();$('#warcde_from_add').on('change',function(){floors('warehouse_floor_id_from_add',$(this).val(),'');refresh('add');});$('#warcde_to_add').on('change',function(){floors('warehouse_floor_id_to_add',$(this).val(),'');});$('#warehouse_floor_id_from_add').on('change',function(){refresh('add');});$('#warcde_from_edit').on('change',function(){floors('warehouse_floor_id_from_edit',$(this).val(),'');refresh('edit');});$('#warcde_to_edit').on('change',function(){floors('warehouse_floor_id_to_edit',$(this).val(),'');});$('#warehouse_floor_id_from_edit').on('change',function(){refresh('edit');});$('#trndte_1').on('change',function(){refresh('add');refresh('edit');});$('#itm_view').on('keypress',function(e){if(e.key==='Enter'||e.keyCode===13){e.preventDefault();search_itm_func_inmodal();}});$('#itmcde_add').on('keypress',function(e){if(e.key==='Enter'||e.keyCode===13){e.preventDefault();search_itm_func('add');}});});
</script>
